import React, { useState, useCallback, useRef } from 'react';
import { Box, Button, Alert, CircularProgress, Typography } from '@mui/material';
import { Save as SaveIcon, CloudUpload as UploadIcon } from '@mui/icons-material';

const FAWForm = ({
  initialData = {},
  onSave,
  onValidate,
  validationRules = {},
  children,
  sx = {},
  saveButtonText = "Save",
  validateButtonText = "Validate",
  showValidateButton = true,
  autoSave = false,
  autoSaveDelay = 2000,
  ...props
}) => {
  // Form state management
  const [formData, setFormData] = useState(initialData);
  const [errors, setErrors] = useState({});
  const [isLoading, setIsLoading] = useState(false);
  const [isValidating, setIsValidating] = useState(false);
  const [isValid, setIsValid] = useState(false);
  const [saveStatus, setSaveStatus] = useState(null); // 'success', 'error', null
  const [validationResults, setValidationResults] = useState([]);
  
  // Auto-save timer ref
  const autoSaveTimer = useRef(null);
  const formRef = useRef(null);

  // Update form field value
  const updateField = useCallback((fieldName, value) => {
    setFormData(prev => ({
      ...prev,
      [fieldName]: value
    }));

    // Clear field-specific error when user starts typing
    if (errors[fieldName]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[fieldName];
        return newErrors;
      });
    }

    // Auto-save functionality
    if (autoSave && onSave) {
      clearTimeout(autoSaveTimer.current);
      autoSaveTimer.current = setTimeout(() => {
        handleSave(true); // Silent auto-save
      }, autoSaveDelay);
    }
  }, [errors, autoSave, autoSaveDelay, onSave]);

  // Client-side validation
  const validateForm = useCallback(() => {
    const newErrors = {};
    
    Object.entries(validationRules).forEach(([fieldName, rules]) => {
      const value = formData[fieldName];
      
      if (rules.required && (!value || value.toString().trim() === '')) {
        newErrors[fieldName] = `${rules.label || fieldName} is required`;
      }
      
      if (value && rules.minLength && value.toString().length < rules.minLength) {
        newErrors[fieldName] = `${rules.label || fieldName} must be at least ${rules.minLength} characters`;
      }
      
      if (value && rules.maxLength && value.toString().length > rules.maxLength) {
        newErrors[fieldName] = `${rules.label || fieldName} must not exceed ${rules.maxLength} characters`;
      }
      
      if (value && rules.pattern && !rules.pattern.test(value)) {
        newErrors[fieldName] = rules.errorMessage || `${rules.label || fieldName} format is invalid`;
      }
      
      if (rules.custom && typeof rules.custom === 'function') {
        const customError = rules.custom(value, formData);
        if (customError) {
          newErrors[fieldName] = customError;
        }
      }
    });
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData, validationRules]);

  // Handle validation (similar to ASP.NET validate button)
  const handleValidate = async () => {
    try {
      setIsValidating(true);
      setSaveStatus(null);
      
      // Client-side validation first
      const isClientValid = validateForm();
      
      if (!isClientValid) {
        setIsValid(false);
        return;
      }
      
      // Server-side validation if provided
      if (onValidate && typeof onValidate === 'function') {
        const validationResult = await onValidate(formData);
        
        if (validationResult.success) {
          setIsValid(true);
          setValidationResults(validationResult.results || []);
          setSaveStatus('validation-success');
        } else {
          setIsValid(false);
          setErrors(validationResult.errors || {});
          setValidationResults(validationResult.results || []);
          setSaveStatus('validation-error');
        }
      } else {
        setIsValid(true);
        setSaveStatus('validation-success');
      }
      
    } catch (error) {
      console.error('Validation error:', error);
      setSaveStatus('validation-error');
      setIsValid(false);
    } finally {
      setIsValidating(false);
    }
  };

  // Handle save (similar to ASP.NET import after validation)
  const handleSave = async (silent = false) => {
    try {
      if (!silent) {
        setIsLoading(true);
        setSaveStatus(null);
      }
      
      // Validate before saving
      if (!isValid && !silent) {
        await handleValidate();
        if (!isValid) {
          return;
        }
      }
      
      // Call save function
      if (onSave && typeof onSave === 'function') {
        const saveResult = await onSave(formData);
        
        if (saveResult.success) {
          setSaveStatus('success');
          if (!silent) {
            // Form saved successfully
          }
        } else {
          setSaveStatus('error');
          setErrors(saveResult.errors || {});
        }
      }
      
    } catch (error) {
      console.error('Save error:', error);
      setSaveStatus('error');
    } finally {
      if (!silent) {
        setIsLoading(false);
      }
    }
  };

  // Handle form submission
  const handleSubmit = (e) => {
    e.preventDefault();
    if (isValid) {
      handleSave();
    } else {
      handleValidate();
    }
  };

  // Enhanced children with form context
  const enhancedChildren = React.Children.map(children, child => {
    if (React.isValidElement(child)) {
      return React.cloneElement(child, {
        formData,
        updateField,
        errors,
        isLoading: isLoading || isValidating,
        ...child.props
      });
    }
    return child;
  });

  return (
    <Box component="form" ref={formRef} onSubmit={handleSubmit} sx={{ ...sx }} {...props}>
      {/* Status Messages */}
      {saveStatus === 'success' && (
        <Alert severity="success" sx={{ mb: 2 }}>
          Form saved successfully!
        </Alert>
      )}
      
      {saveStatus === 'error' && (
        <Alert severity="error" sx={{ mb: 2 }}>
          Failed to save form. Please check the errors and try again.
        </Alert>
      )}
      
      {saveStatus === 'validation-success' && (
        <Alert severity="info" sx={{ mb: 2 }}>
          Validation passed! You can now save the form.
        </Alert>
      )}
      
      {saveStatus === 'validation-error' && (
        <Alert severity="warning" sx={{ mb: 2 }}>
          Validation failed. Please fix the errors below.
        </Alert>
      )}

      {/* Validation Results Display */}
      {validationResults.length > 0 && (
        <Box sx={{ mb: 2 }}>
          <Typography variant="h6" gutterBottom>
            Validation Results
          </Typography>
          {validationResults.map((result, index) => (
            <Alert 
              key={index} 
              severity={result.isValid ? (result.hasWarnings ? 'warning' : 'success') : 'error'}
              sx={{ mb: 1 }}
            >
              <Typography variant="subtitle2">
                {result.targetType || `Validation ${index + 1}`}
              </Typography>
              {result.errors?.map((error, i) => (
                <Typography key={i} variant="body2" color="error">
                  • {error}
                </Typography>
              ))}
              {result.warnings?.map((warning, i) => (
                <Typography key={i} variant="body2" color="warning.main">
                  • {warning}
                </Typography>
              ))}
            </Alert>
          ))}
        </Box>
      )}

      {/* Form Fields */}
      {enhancedChildren}

      {/* Action Buttons */}
      <Box sx={{ display: 'flex', gap: 2, mt: 3, justifyContent: 'flex-end' }}>
        {showValidateButton && (
          <Button
            type="button"
            variant="outlined"
            color="primary"
            onClick={handleValidate}
            disabled={isValidating || isLoading}
            startIcon={isValidating ? <CircularProgress size={20} /> : <UploadIcon />}
          >
            {isValidating ? 'Validating...' : validateButtonText}
          </Button>
        )}
        
        <Button
          type="submit"
          variant="contained"
          color="primary"
          disabled={(!isValid && !autoSave) || isLoading || isValidating}
          startIcon={isLoading ? <CircularProgress size={20} /> : <SaveIcon />}
        >
          {isLoading ? 'Saving...' : saveButtonText}
        </Button>
      </Box>

      {/* Auto-save indicator */}
      {autoSave && (
        <Typography variant="caption" color="text.secondary" sx={{ mt: 1, display: 'block' }}>
          Auto-save enabled (saves every {autoSaveDelay / 1000} seconds)
        </Typography>
      )}
    </Box>
  );
};

export default FAWForm; 